window.__QUIZ_DATA__=[{"id":"theory>Geography>2020>Section A>1>a","subject":"Geography","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline five reasons for industrial localization","images":[],"marking_scheme":"Reasons for industrial localization  - Climatic Conditions  - Nearness to Raw Materials  - Nearness to Sources of power    - Nearness to Markets  - Adequate and Trained Labour  - Availability of Finance  - Momentum of an Early Start  - Political Patronage","marks":"10","difficulty":"2"},{"id":"theory>Geography>2020>Section A>1>b","subject":"Geography","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Explain five benefits of establishing manufacturing industries in rural areas","images":[],"marking_scheme":"- It checks the drift of young people from the rural areas to the towns and cities.              - Labour is likely to be cheaper in the rural areas.  - Transportation and accommodation problems of staff are likely to be less acute.  - The industrial atmosphere would be more peaceful, free from traffic congestion.   - Land is likely to be more easily available in the rural areas.  - It will be easier for the firm to get raw materials in the rural areas.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2020>Section A>2>a","subject":"Geography","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Outline four characteristics of nucleated settlement","images":[],"marking_scheme":"-\tIn nucleated settlements, people live close to their neighbors.   -\tThis proximity makes communication quicker and easier than in linear and dispersed settlements.  -\t Because people are closer together, it is also easier to perform joint tasks such as the buying and selling of goods and services.  -\tCreating a centralized governing body also becomes a more simplified process because of the proximity of people to important locations in their settlement.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2020>Section A>2>b","subject":"Geography","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Identify four functions of cities in the world","images":[],"marking_scheme":"-\tCommand and control points in the global economy.  -\tKey location for a full range of service.  -\tKey location for specialized services.  -\tMarket for a full range of good and services.  -\tDistinctive and prestigious lifestyle","marks":"6","difficulty":"2"},{"id":"theory>Geography>2020>Section A>2>c","subject":"Geography","year":"2020","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"State four factors that favor the growth of settlements","images":[],"marking_scheme":"-\tBody of water (transportation routes, water for drinking and farming)  -\tFlat land (easy to build).  -\t  Fertile soil (for crops) .   -\tForests (timber and housing).  -\tPeople who share a common language for effective communication.    -\tReligion or culture  social network or support  quality of life  employment.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2020>Section A>3>a","subject":"Geography","year":"2020","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write explainatory notes on the following:    three characteristics of ocean transportation","images":[],"marking_scheme":"-\tIt is cheap compare to other type of transportation  The natural structure of the ship's navigation channel, the ship's transportation capacity is large, the port equipment is generally built by the government, the ship is durable and saves fuel, so the unit transportation cost of the goods is relatively low. Due to the above characteristics, the transportation of marine cargo is basically adapted to the transportation of various goods, such as oil wells, trains, rolling stock and other super-significant goods. Other modes of transportation cannot be shipped, and ships can generally be shipped.    - The ability of sea freight to pass.  Sea Freight uses natural waterways in all directions. Unlike trains and cars, which are subject to orbits and roads, their passing capacity exceeds that of other modes of transportation. If the political, economic, military and other conditions change, it is also possible to change the route to the destination port that is conducive to loading and unloading.    - Large volume of Sea Freight  International cargo transportation is the exchange of goods around the world. Geographical location and geographical conditions determine that marine cargo transportation is the main means of international Sea Freight .","marks":"8","difficulty":"2"},{"id":"theory>Geography>2020>Section A>3>b","subject":"Geography","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write explainatory notes on the following:  three advantages of water transportation","images":[],"marking_scheme":"- Less Maintenance Cost:  Maintenance cost in rail and road transport is quite high but maintenance cost of water transport is quite less.    - Cheap:  The transport channel is quite cheap as compared rail and road Transport.    -  Useful for Bulky Goods:  Heavy and bulky goods can be transported easily at little cost through water transport.    -Useful During Natural Calamities:  During natural calamities like flood and rains, when rail and road transport is disrupted, relief operations can be operated through water transport.  -\tHelpful in Defence:  Development of shipping is essential for the Defence of the country also. It is also called second line of Defence.  -\tImportant for Foreign Trade:  Water transport plays important role in foreign trade. India's foreign trade is mainly dependent on water transport.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2020>Section A>3>c","subject":"Geography","year":"2020","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write explainatory notes on the following:  four ways in which poor transportation network can hinder economic development of a country.","images":[],"marking_scheme":"-\tUnavailability of raw materials for industries.    Transport system helps to send raw materials, fuel and machineries to different industries at right time and runs the industry. But poor transportation makes it difficult for raw material to be available for the industries which in turn affect the economy of a country.    -\tIneffective response to emergencies.    A developed transport system is necessary to send necessary helps to the affected people during the period of natural calamities.    -\tHigh cost of goods and services   Poor transportation causes the price of commodity to increase which subsequently affect the economic growth of a country  -\tPoor security infrastructure  Poor transportation affects the security responsibility of a country which in turn leads to a poor economical state of a country.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2020>Section B>4>a>i","subject":"Geography","year":"2020","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map show and name:    the Rainforest Belt;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Geography>2020>Section B>4>a>ii","subject":"Geography","year":"2020","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map show and name:  the Sahel Savannah Belt;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Geography>2020>Section B>4>a>iii","subject":"Geography","year":"2020","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of Nigeria. On the map show and name:  Ibadan","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"2"},{"id":"theory>Geography>2020>Section B>4>b","subject":"Geography","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Outline three characteristics of the rainforest belt.","images":[],"marking_scheme":"- Very wet with over 2,000 mm of rainfall per year.               -The warm and very wet climate provides perfect conditions for plant growth.  - The wide range of plant species supports many different animals, birds and insects.  - Species have adapted to the conditions of the rainforest, e.g. trees and plants have shallow-reaching roots to absorb nutrients from the thin fertile layer in the soil.","marks":"3","difficulty":"1"},{"id":"theory>Geography>2020>Section B>4>c","subject":"Geography","year":"2020","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"In what four ways in the rainforest vegetation important to the economy of Nigeria?","images":[],"marking_scheme":"- It provides food for the country.  - Provision of wood for construction purposes.  - Source of timber for export/foreign exchange.  - Provision of  jobs for hunters, lumbermen etc.  - It provides raw materials for industries  -Provides herbs for medicine.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2020>Section B>5>a>i","subject":"Geography","year":"2020","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw an outline map of Nigeria. On the map, locate and name:    the interior coastland of western Nigeria;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2020>Section B>5>a>ii","subject":"Geography","year":"2020","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw an outline map of Nigeria. On the map, locate and name:  the coastal plain;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2020>Section B>5>a>iii","subject":"Geography","year":"2020","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Draw an outline map of Nigeria. On the map, locate and name:  the Niger Delta;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2020>Section B>5>a>iv","subject":"Geography","year":"2020","type":"Theory","sub_label":"iv","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Draw an outline map of Nigeria. On the map, locate and name:  Port Harcourt","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2020>Section B>5>b","subject":"Geography","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Highlight three benefits derived from coastlands of Nigeria.","images":[],"marking_scheme":"-\tSource of transportation  -\tProvision of water foods   -\tServes as a security base for the country  -\tIt helps to boost the countries' economy by an active marketing system.","marks":"3","difficulty":"1"},{"id":"theory>Geography>2020>Section B>5>c","subject":"Geography","year":"2020","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Identify three problems hindering the development of seaports in Nigeria.","images":[],"marking_scheme":"-           Lack of infrastructure.  -\tIntegrated transportation system.    -\tIncentives for investors.  -\tUnfriendly tax policies.  -\tHigh corruption rate.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2020>Section B>6>a>i","subject":"Geography","year":"2020","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Name two sources of:    thermal energy in Nigeria;","images":[],"marking_scheme":"Thermal energy source   - The living organisms burn food (chemical energy) in their bodies to generate body heat (thermal energy).    - A composter is another source of thermal energy. Decomposers break down food and as these chemical changes occur, thermal energy is produced, which in turn helps speed up the process of decomposition.","marks":"4","difficulty":"1"},{"id":"theory>Geography>2020>Section B>6>a>ii","subject":"Geography","year":"2020","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Name two sources of:  Renewable energy in Nigeria","images":[],"marking_scheme":"-Solar energy  -Wind energy  - Hydro energy  - Tidal energy  - Geothermal energy  - Biomass energy","marks":"4","difficulty":"1"},{"id":"theory>Geography>2020>Section B>6>b","subject":"Geography","year":"2020","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Identify four problems hindering the deveopment of thermal energy in Nigeria.","images":[],"marking_scheme":"-       shortage of gas supply for thermal plants   -\t High levels of unpaid electricity bills.  -\tThe country's outdated and poorly maintained transmission network, which the government still owns but put under private management.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2020>Section B>6>c","subject":"Geography","year":"2020","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Suggest solutions to the problems identified in 6(b).","images":[],"marking_scheme":"-\tSufficient gas should be supply for thermal plants to function effectively.  -\tThe government should subsidize the electricity bills of thermal plant in other to encourage their operations   -\tCommunication network should be restructure for efficient communication.","marks":"4","difficulty":"2"}];